/** @param {string} title @param {string} body @returns {string} */
function generatedBlock(title, body) {
	return `${GENERATED_HEADER}\n# ${title}\n\n${body.trim()}\n`;
}

/** @param {string} title @param {string} canonical @returns {string} */
function materializedInstructions(title, canonical) {
	return generatedBlock(
		title,
		`Source: \`AGENTS.md\`. Regenerate with \`bun run generate:agents\`.\n\n${canonical.trim()}\n`,
	);
}

/** @param {string} title @param {string} importLine @param {string} extra @returns {string} */
function wrapperInstructions(title, importLine, extra) {
	return generatedBlock(
		title,
		`${importLine}\n\n${extra.trim()}\n\nRegenerate with \`bun run generate:agents\`.`,
	);
}

/** @param {string} canonical @returns {string} */
function cursorRule(canonical) {
	return `---\ndescription: WebCPU EASEL.js agent contract for Cursor\nalwaysApply: true\n---\n\n${materializedInstructions("WebCPU EASEL.js Cursor Rule", canonical)}`;
}

/** @param {string} canonical @returns {string} */
function augmentRule(canonical) {
	return `---\ntype: always\ndescription: WebCPU EASEL.js agent contract\n---\n\n${materializedInstructions("WebCPU EASEL.js Augment Rule", canonical)}`;
}

/** @returns {string} */
function supportMatrix() {
	const rows = SUPPORT_SOURCES.map(
		(entry) =>
			`| ${entry.tool} | \`${entry.path}\` | ${entry.mode} | [docs](${entry.source}) | ${entry.notes} |`,
	).join("\n");
	return `${GENERATED_HEADER}\n# Agent Platform Support Matrix\n\nThis repository uses \`AGENTS.md\` as the canonical source. Platform files are generated wrappers or generated materialized copies so tool-specific instruction surfaces do not drift.\n\nRun \`bun run generate:agents\` after changing \`AGENTS.md\`.\n\n| Platform | File or context path | Support mode | Source | Notes |\n| --- | --- | --- | --- | --- |\n${rows}\n\n## Rules\n\n- Do not edit generated platform files by hand.\n- Do not symlink \`CLAUDE.md\`; this repository requires a real file.\n- Prefer native imports only where the platform documents import support.\n- Use generated materialized rules when a platform reads a fixed file but does not document import resolution.\n- If a platform has no verified repository rule-file standard, document the fallback instead of inventing one.\n`;
}

/** @param {string} path @returns {Promise<string>} */
async function read(path) {
	return await readFile(join(ROOT, path), "utf8");
}

/** @param {string} path @param {string} content @returns {Promise<void>} */
async function write(path, content) {
	await mkdir(dirname(join(ROOT, path)), { recursive: true });
	await writeFile(join(ROOT, path), content);
}

/** @returns {Promise<Map<string, string>>} */
async function expectedFiles() {
	const canonical = await read("AGENTS.md");
	return new Map([
		[
			"CLAUDE.md",
			wrapperInstructions(
				"Claude Code Instructions",
				"@AGENTS.md",
				"Claude Code reads this real wrapper file, then imports canonical repository instructions from AGENTS.md.",
			),
		],
		[
			"GEMINI.md",
			wrapperInstructions(
				"Gemini CLI Instructions",
				"@./AGENTS.md",
				"Gemini CLI processes @file imports in GEMINI.md. Keep repository rules in AGENTS.md.",
			),
		],
		[
			".github/copilot-instructions.md",
			materializedInstructions("GitHub Copilot Instructions", canonical),
		],
		[".cursor/rules/webcpu-easel.mdc", cursorRule(canonical)],
		[".rules", materializedInstructions("Zed Rules", canonical)],
		[
			".aiassistant/rules/webcpu-easel.md",
			materializedInstructions("JetBrains AI Assistant Rule", canonical),
		],
		[
			".junie/AGENTS.md",
			materializedInstructions("JetBrains Junie Agent Instructions", canonical),
		],
		[
			".clinerules/00-webcpu-easel.md",
			materializedInstructions("Cline Workspace Rule", canonical),
		],
		[
			".roo/rules/00-webcpu-easel.md",
			materializedInstructions("Roo Code Workspace Rule", canonical),
		],
		[".augment/rules/webcpu-easel.md", augmentRule(canonical)],
		["docs/agent-platforms.md", supportMatrix()],
	]);
}

/** @param {Map<string, string>} files @returns {Promise<void>} */
async function check(files) {
	const mismatches = [];
	for (const [path, expected] of files) {
		let actual = "";
		try {
			actual = await read(path);
		} catch {
			mismatches.push(`${path} missing`);
			continue;
		}
		if (actual !== expected) mismatches.push(`${path} drifted`);
	}
	if (mismatches.length > 0) {
		throw new Error(
			`generated agent surfaces are stale:\n${mismatches.join("\n")}`,
		);
	}
}

async function main() {
	const files = await expectedFiles();
	if (CHECK) {
		await check(files);
		console.log("Generated agent surfaces are current.");
		return;
	}
	for (const [path, content] of files) await write(path, content);
	console.log(`Generated ${files.size} agent instruction surfaces.`);
}

main().catch((error) => {
	console.error(error.message);
	process.exitCode = 1;
});
